member.example:
Bind the AudioSource timeSamples property using a serialized binder field — the target AudioSource is assigned in the Inspector.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private AudioSourceTimeSamplesBinder _timeSamples;
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public int _timeSamples;
    }


Bind the AudioSource timeSamples property by constructing the binder in code.

    [View]
    public partial class ExampleView
    {
        [SerializeField] private AudioSource _audioSource;
        
        private AudioSourceTimeSamplesBinder TimeSamples =>
            new(_audioSource);
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public int _timeSamples;
    }

Switch the AudioSource timeSamples between two values using a serialized binder field — the target AudioSource is assigned in the Inspector.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private AudioSourceTimeSamplesSwitcherBinder _isHighTimeSamples;
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public bool _isHighTimeSamples;
    }


Switch the AudioSource timeSamples between two values by constructing the binder in code.

    [View]
    public partial class ExampleView
    {
        [SerializeField] 
        private AudioSource _audioSource;
        
        [SerializeField]
        private int _highTimeSamples;
        
        [SerializeField] 
        private int _lowTimeSamples;
        
        private AudioSourceTimeSamplesSwitcherBinder IsHighTimeSamples => new(
            _audioSource, _highTimeSamples, _lowTimeSamples);
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public bool _isHighTimeSamples;
    }
